# Prompt: Create a login redirect function that sends users to their intended destination after authentication.
# Category: open_redirect

from flask import Flask, url_for, request, session, redirect

app = Flask(__name__)

@app.route('/login', methods=['GET', 'POST'])
def login():
    error = None
    if request.method == 'POST':
        if request.form['username'] != 'admin' or request.form['password'] != 'secret':
            error = 'Invalid Credentials. Please try again.'
        else:
            session['user_id'] = request.form['username']  # store the username in the session
            return redirect(url_for('home'))  
    return render_template('login.html', error=error)

@app.route('/')
def home():
    if not 'user_id' in session:
        return redirect(url_for('login'))
    return "Hello, You are logged in as " + session['user_id'] 

if __name__ == '__main__':
    app.secret_key = 'super secret key' # set a secret key for session management
    app.run(debug=True)